mapper.update:
UPDATE event_consume_record
SET status     = 'SUCCESS',
    updated_at = NOW()
WHERE event_id      = #{eventId}
  AND consumer_name = #{consumerName}

UPDATE event_consume_record
SET status     = 'FAILED',
    error_msg  = #{errorMsg},
    updated_at = NOW()
WHERE event_id      = #{eventId}
  AND consumer_name = #{consumerName}
